    MSG_QUERY_OTHERS_BETINFO_RESP = 15252;//查询其他玩家的下注信息回复

    MSG_UNDO_BET_REQ = 15253;//撤销上一次下注操作

    MSG_REDO_BET_REQ = 15254;//重做上一次撤销的下注操作

